{
  "mode": "method",
  "tests": [
    {
      "name": "default_schema_fallback",
      "input": {},
      "output": "public",
      "notes": "Tests the fallback to the default 'public' schema when POSTGRES_SCHEMA is not set."
    },
    {
      "name": "custom_schema_configuration",
      "input": {
        "POSTGRES_SCHEMA": "custom_schema"
      },
      "output": "custom_schema",
      "notes": "Validates that the application correctly uses the custom schema provided in the environment variable."
    },
    {
      "name": "migration_with_custom_schema",
      "input": {
        "POSTGRES_SCHEMA": "migration_schema"
      },
      "output": "migrations run successfully",
      "notes": "Ensures that migrations are executed correctly on a custom schema."
    },
    {
      "name": "migration_without_schema",
      "input": {},
      "output": "migrations run successfully on public",
      "notes": "Tests that migrations run correctly on the default public schema when no custom schema is provided."
    },
    {
      "name": "invalid_schema_name",
      "input": {
        "POSTGRES_SCHEMA": "invalid/schema"
      },
      "output": "error",
      "notes": "Checks the application's response to an invalid schema name format."
    },
    {
      "name": "schema_documentation_update",
      "input": {},
      "output": "README.md updated",
      "notes": "Verifies that the README.md contains updated instructions for schema configuration."
    },
    {
      "name": "environment_variable_absence",
      "input": {},
      "output": "public",
      "notes": "Confirms that absence of the POSTGRES_SCHEMA variable defaults to 'public' schema."
    },
    {
      "name": "multiple_environment_support",
      "input": {
        "POSTGRES_SCHEMA": "dev_schema"
      },
      "output": "dev_schema",
      "notes": "Tests that the application can support different schemas in various environments."
    }
  ],
  "assumptions": "The application is configured to read environment variables correctly.",
  "notes": "Ensure that the PostgreSQL server is accessible during testing."
}
